INSERT INTO HR_ADDRESS_MATTERS (
    ADDRESS_NO, PERSON_ID, ADDRESS_TYPE, EFFECTIVE_START_DATE, ADDRESS_CONTENT,
    ACTIVITY, NATIONALITY,
    CREATE_DATE, CREATED_BY, CREATED_IP, UPDATE_DATE, UPDATED_BY, UPDATED_IP
) VALUES (
    HR_ADDRESS_MATTERS_SEQ.NEXTVAL, #{personId}, #{addressType}, #{effectiveStartDate}, #{addressContent},
    1, #{nationality},
    SYSDATE, #{adminID}, #{adminIP}, SYSDATE, #{adminID}, #{adminIP}
)

