UPDATE HR_ADDRESS_MATTERS 
SET ACTIVITY = '0',
    UPDATE_DATE = SYSDATE, 
    UPDATED_BY = #{adminID}, 
    UPDATED_IP = #{adminIP} 
WHERE ADDRESS_NO = #{addressNo}
